#include <bits/stdc++.h>
using namespace std;
const int N=2005;
int n,a[N],dp[N][N],s[N];
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
        s[i]=s[i-1]+a[i];
    }
    for(int len=1;len<=n;len++)
    {
        for(int l=1,r=l+len-1;r<=n;l++,r++)
        {
            int t=n-len+1;
            dp[l][r]=max(dp[l+1][r]+a[l]*t,dp[l][r-1]+a[r]*t);
        }
    }
    cout<<dp[1][n];
    return 0;
}
